import{_ as s,o as e,c as n,a0 as i}from"./chunks/framework.BjpW4enL.js";const u=JSON.parse('{"title":"ADR 0015: Navegação por Níveis de Abstração (Zoom)","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/0015-zoom-stateful-protocol.md","filePath":"Z_Archive/wiki_legacy/archive/0015-zoom-stateful-protocol.md","lastUpdated":1783623176000}'),o={name:"Z_Archive/wiki_legacy/archive/0015-zoom-stateful-protocol.md"};function t(l,a,r,p,d,c){return e(),n("div",null,[...a[0]||(a[0]=[i(`<h1 id="adr-0015-navegacao-por-niveis-de-abstracao-zoom" tabindex="-1">ADR 0015: Navegação por Níveis de Abstração (Zoom) <a class="header-anchor" href="#adr-0015-navegacao-por-niveis-de-abstracao-zoom" aria-label="Permalink to &quot;ADR 0015: Navegação por Níveis de Abstração (Zoom)&quot;">​</a></h1><p><strong>Data:</strong> 2026-06-09 <strong>Status:</strong> Revisado — L3 Plástica via Comunidades T4 <strong>Área:</strong> Arquitetura MCP + Protocolo de Consulta</p><h2 id="contexto" tabindex="-1">Contexto <a class="header-anchor" href="#contexto" aria-label="Permalink to &quot;Contexto&quot;">​</a></h2><p>O NEXUS possui 4 níveis de abstração (L0-L3), armazenados em <code>abstractions</code> no PostgreSQL com vectors em Qdrant, e relações topológicas (T4) em <code>agent_links</code>. O MCP server expõe tools stateless: <code>nexus_query</code> (T3), <code>nexus_adjacent</code> (T4 grafo).</p><h3 id="o-problema" tabindex="-1">O Problema <a class="header-anchor" href="#o-problema" aria-label="Permalink to &quot;O Problema&quot;">​</a></h3><p>Um agente LLM que chega ao NEXUS precisa alternar entre:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Visão compacta:  &quot;essência do sistema em 300 tokens&quot;</span></span>
<span class="line"><span>Aprofundamento: &quot;detalhes do enrichment&quot;</span></span>
<span class="line"><span>Código fonte:   &quot;implementação do merge&quot;</span></span></code></pre></div><p>Hoje não há como navegar entre níveis de abstração numa única consulta. Cada chamada de tool é independente e plana.</p><h3 id="por-que-subir-pra-l3-e-dificil" tabindex="-1">Por Que Subir pra L3 é Difícil <a class="header-anchor" href="#por-que-subir-pra-l3-e-dificil" aria-label="Permalink to &quot;Por Que Subir pra L3 é Difícil&quot;">​</a></h3><p>Tentamos gerar L3 por <strong>blob</strong> (arquivo individual). O problema é que:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Arquivos (blobs)                    Domínios Lógicos</span></span>
<span class="line"><span>─────────────────                   ────────────────</span></span>
<span class="line"><span>enrich.rs ─────────────────┐</span></span>
<span class="line"><span>models.rs  ────────────────┤── &quot;Enrichment Pipeline&quot;</span></span>
<span class="line"><span>weaver.rs  ────────────────┘</span></span>
<span class="line"><span>                              </span></span>
<span class="line"><span>mcp_server.py ─────────────┐── &quot;MCP Protocol&quot;</span></span>
<span class="line"><span>mcp_stigmergy.py ──────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>l3_blob_knowledge.py ────── &quot;L3 Generation&quot; (isolado)</span></span></code></pre></div><p><strong>Blob ≠ Domínio.</strong> Um arquivo individual não contém um domínio completo. L3 por blob gera &quot;o que esse arquivo faz&quot; — não &quot;o que o enriquecimento é&quot;. Para ter L3 de domínio, precisamos de <strong>síntese multi-arquivo</strong>.</p><h3 id="por-que-ast-nao-resolve" tabindex="-1">Por Que AST Não Resolve <a class="header-anchor" href="#por-que-ast-nao-resolve" aria-label="Permalink to &quot;Por Que AST Não Resolve&quot;">​</a></h3><p>A AST (L1) é <strong>estrutura sintática</strong>: call graph, imports, types. Ela te dá:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>enrich.rs models.rs       enrich.rs → weaver.rs</span></span>
<span class="line"><span>  chamadas    tipos         chamadas</span></span></code></pre></div><p>Mas não te dá:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;enrichment pipeline&quot; = enrich + models + weaver</span></span>
<span class="line"><span>                        ^--- propósito, não estrutura</span></span></code></pre></div><p>AST densifica arestas T4 (call graph vira <code>agent_links</code>), mas <strong>quem define o domínio é o propósito, não a sintaxe</strong>.</p><h2 id="decisao-l3-plastica-via-comunidades-t4" tabindex="-1">Decisão: L3 Plástica via Comunidades T4 <a class="header-anchor" href="#decisao-l3-plastica-via-comunidades-t4" aria-label="Permalink to &quot;Decisão: L3 Plástica via Comunidades T4&quot;">​</a></h2><p><strong>Abandonar L3 fixa por blob.</strong> Em vez disso, L3 <strong>emerge</strong> do grafo T4:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>           ┌──────────────────────────────┐</span></span>
<span class="line"><span>           │ agent_links (T4, 3.832 arr.) │</span></span>
<span class="line"><span>           │  successor, semantic_bridge, │</span></span>
<span class="line"><span>           │  derived_from                │</span></span>
<span class="line"><span>           └──────────┬───────────────────┘</span></span>
<span class="line"><span>                      │ community detection</span></span>
<span class="line"><span>                      ▼</span></span>
<span class="line"><span>           ┌──────────────────────────────┐</span></span>
<span class="line"><span>           │ Comunidades (clusters T4)    │</span></span>
<span class="line"><span>           │  domínio A: {chunks E,R,M,W} │</span></span>
<span class="line"><span>           │  domínio B: {chunks M,S,S}   │</span></span>
<span class="line"><span>           └──────────┬───────────────────┘</span></span>
<span class="line"><span>                      │ walk + synthesize</span></span>
<span class="line"><span>                      ▼</span></span>
<span class="line"><span>           ┌──────────────────────────────┐</span></span>
<span class="line"><span>           │ L3 por comunidade            │</span></span>
<span class="line"><span>           │  (multi-blob, multi-arquivo) │</span></span>
<span class="line"><span>           │  armazenado OU gerado on-fly │</span></span>
<span class="line"><span>           └──────────────────────────────┘</span></span></code></pre></div><h3 id="mecanismo" tabindex="-1">Mecanismo <a class="header-anchor" href="#mecanismo" aria-label="Permalink to &quot;Mecanismo&quot;">​</a></h3><ol><li><strong>Community detection</strong> no grafo <code>agent_links</code> (LPA ou walktrap) → clusters naturais: {enrichment}, {query}, {mcp}, {l3}, ...</li><li><strong>Cada cluster = candidato a domínio L3</strong> → não importa se os arquivos estão em diretórios diferentes</li><li><strong>L3 é gerado por cluster</strong> (multi-blob synthesis) → pega todos chunks L2 do cluster, gera síntese unificada</li><li><strong>L3 pode ser fixa OU on-the-fly:</strong><ul><li><strong>Fixa:</strong> abstractions level=3, domain=<code>&amp;lt;cluster&amp;gt;</code>, revisível</li><li><strong>On-the-fly:</strong> walk parametrizada + síntese no momento da query</li></ul></li></ol><h3 id="vantagem-l3-plastica" tabindex="-1">Vantagem: L3 Plástica <a class="header-anchor" href="#vantagem-l3-plastica" aria-label="Permalink to &quot;Vantagem: L3 Plástica&quot;">​</a></h3><p>L3 on-the-fly é <strong>plástica</strong> porque:</p><ul><li>Mesma walk hoje → cluster A. Semana que vem com +dados → cluster A&#39;.</li><li>O grafo T4 é a fonte da verdade. L3 é <strong>view</strong>, não tabela.</li><li>A AST alimenta T4 (novos imports = novas arestas), mas o cluster emerge.</li><li><strong>Plástico = adaptável sem regenerar abstração.</strong></li></ul><h3 id="o-papel-da-ast-l1" tabindex="-1">O Papel da AST (L1) <a class="header-anchor" href="#o-papel-da-ast-l1" aria-label="Permalink to &quot;O Papel da AST (L1)&quot;">​</a></h3><p>AST não resolve domínio, mas <strong>densifica o grafo T4</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>agent_links hoje:</span></span>
<span class="line"><span>  successor (L2→L2 vizinhos)</span></span>
<span class="line"><span>  semantic_bridge (L2→L2 cross-file)</span></span>
<span class="line"><span>  derived_from (L3→L2)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>agent_links com AST:</span></span>
<span class="line"><span>  call_graph (L1→L1 chamadas)</span></span>
<span class="line"><span>  type_ref (L1→L1 tipos compartilhados)</span></span></code></pre></div><p>Mais arestas → comunidades mais precisas → L3 melhor. AST é <strong>matéria-prima para o T4</strong>, não substituta para L3.</p><h2 id="operador-revisado" tabindex="-1">Operador Revisado <a class="header-anchor" href="#operador-revisado" aria-label="Permalink to &quot;Operador Revisado&quot;">​</a></h2><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">nexus_query(query, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">depth</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">.3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">cluster</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">True</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  → depth controla quantas hops no T4</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  → cluster</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">True</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ativa agrupamento por comunidade</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  → retorno: contexto organizado por domínio (cluster), não por arquivo</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Exemplo:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  nexus_query(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;enrichment&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">depth</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">cluster</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">True</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    → cluster: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Enrichment Pipeline&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">12</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> chunks, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> arquivos)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    → L3: síntese do domínio</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    → L2 chunks: merge, embed, upsert</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    → L1: enrich.rs::</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">585</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">717</span></span></code></pre></div><h2 id="caminhos-considerados" tabindex="-1">Caminhos Considerados <a class="header-anchor" href="#caminhos-considerados" aria-label="Permalink to &quot;Caminhos Considerados&quot;">​</a></h2><h3 id="l3-fixa-por-blob-tentado" tabindex="-1">L3 fixa por blob (tentado) <a class="header-anchor" href="#l3-fixa-por-blob-tentado" aria-label="Permalink to &quot;L3 fixa por blob (tentado)&quot;">​</a></h3><p>Gerar abstração level=3 para cada blob individual.</p><p><strong>Rejeitado porque:</strong> blob ≠ domínio. L3 por blob é &quot;resumo de arquivo&quot;, não &quot;conhecimento de domínio&quot;. As 4 L3 geradas confirmam: são genéricas.</p><h3 id="l3-fixa-por-diretorio" tabindex="-1">L3 fixa por diretório <a class="header-anchor" href="#l3-fixa-por-diretorio" aria-label="Permalink to &quot;L3 fixa por diretório&quot;">​</a></h3><p>Agrupar blobs do mesmo diretório.</p><p><strong>Rejeitado porque:</strong> diretório ≠ domínio (ex: <code>services/coordinator/src/</code> tem enrichment + query + weaver misturados).</p><h3 id="stateful-6-operadores-handoff-original" tabindex="-1">Stateful 6-operadores (handoff original) <a class="header-anchor" href="#stateful-6-operadores-handoff-original" aria-label="Permalink to &quot;Stateful 6-operadores (handoff original)&quot;">​</a></h3><p>Sessões multi-passo com init/deepen/narrow/context.</p><p><strong>Rejeitado por:</strong> prematuridade. L3 precisa ser validado primeiro. E com L3 plástica on-the-fly, stateful perde sentido — o <code>depth</code> stateless já resolve.</p><h2 id="consequencias" tabindex="-1">Consequências <a class="header-anchor" href="#consequencias" aria-label="Permalink to &quot;Consequências&quot;">​</a></h2><h3 id="positivas" tabindex="-1">Positivas <a class="header-anchor" href="#positivas" aria-label="Permalink to &quot;Positivas&quot;">​</a></h3><ol><li><strong>L3 orgânica</strong> — fronteiras vêm do uso (T4), não do filesystem</li><li><strong>Plástica</strong> — se adapta conforme o grafo evolui</li><li><strong>AST vira insumo, não solução</strong> — seu papel é densificar T4</li><li><strong>Stateless suficiente</strong> — depth + cluster resolve sem sessão</li><li><strong>Community detection é script único</strong> — roda em cima de agent_links</li></ol><h3 id="negativas" tabindex="-1">Negativas <a class="header-anchor" href="#negativas" aria-label="Permalink to &quot;Negativas&quot;">​</a></h3><ol><li><strong>L3 on-the-fly é mais cara</strong> — walk + síntese por query vs lookup</li><li><strong>Community detection periódica</strong> — precisa re-roder se grafo mudar muito</li><li><strong>AST não está linkada no T4 ainda</strong> — call_graph não existe em agent_links</li><li><strong>Precisa de L2 robusto</strong> — L3 emerge de L2; se L2 for fraco, L3 também</li></ol><h3 id="neutras" tabindex="-1">Neutras <a class="header-anchor" href="#neutras" aria-label="Permalink to &quot;Neutras&quot;">​</a></h3><ol><li>Compatível com depth parameter (são ortogonais)</li><li>Community detection pode ser assíncrona (trigger por webhook)</li><li>AST ingestion já acontece — só falta transformar em agent_links</li></ol><h2 id="dados-existentes" tabindex="-1">Dados Existentes <a class="header-anchor" href="#dados-existentes" aria-label="Permalink to &quot;Dados Existentes&quot;">​</a></h2><ul><li><code>agent_links</code>: <strong>3.832 arestas</strong> — base para community detection</li><li><code>abstractions</code> level=2: <strong>1.578 nós</strong> — matéria-prima dos clusters</li><li><code>abstractions</code> level=1: <strong>488 nós</strong> — AST disponível, não linkada no T4</li><li><code>abstractions</code> level=3: <strong>4 nós</strong> — legado da abordagem por blob</li></ul><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><ol><li><strong>Rodar community detection</strong> nos agent_links → ver clusters</li><li><strong>Validar</strong> se os clusters correspondem a domínios reais</li><li><strong>Se clusters coerentes:</strong> gerar L3 por cluster (fixa ou on-the-fly)</li><li><strong>Linkar AST no T4</strong> (call_graph edges em agent_links)</li><li><strong>Adicionar <code>depth</code> + <code>cluster</code></strong> no nexus_query</li></ol><h2 id="referencias" tabindex="-1">Referências <a class="header-anchor" href="#referencias" aria-label="Permalink to &quot;Referências&quot;">​</a></h2><ul><li>AGENTS.md — protocolo estático atual</li><li>ADR 0010: Abstraction Levels and Time</li><li>ADR 0013: Multi-Project Schema Cleanup</li><li><code>docs/handoff/HANDOFF_2026-06-09_ZOOM-PROTOCOL.md</code> — handoff original</li><li><code>scripts/nexus_mcp_stigmergy.py</code> — backend do grafo T4</li><li><code>scripts/nexus_l3_blob_knowledge.py</code> — L3 por blob (legado)</li></ul>`,55)])])}const g=s(o,[["render",t]]);export{u as __pageData,g as default};
